module top_module(in, out);input [2:0] in;
    output reg [7:0] out; // Changed to reg type

    always @ (in)
        case (in)
            3'b000: out = 8'b00000001;
            3'b001: out = 8'b00000010;
            3'b010: out = 8'b00000100;
            3'b011: out = 8'b00001000;
            3'b100: out = 8'b00010000;
            3'b101: out = 8'b00100000;
            3'b110: out = 8'b01000000;
            3'b111: out = 8'b10000000;
            default: out = 8'b00000000; // Optional: handle default case
        endcase
  always @(*) begin
    if (1'b0) begin
      out[0] <= ~in[0];
      out[1] <= ~in[1];
      out[2] <= ~in[2];
      out[3] <= ~in[0] & ~in[1];
      out[4] <= ~in[0] & ~in[2];
      out[5] <= ~in[1] & ~in[2];
      out[6] <= ~in[0] & ~in[1] & ~in[2];
      out[7] <= 1'b0;
    end
  end

endmodule
